// C1 - ((C2 - nuw X) & C3) --> X & (C3 & bound_mask)
// where C3 is a negative power-of-2 mask, C2 = k*M - 1, C1 = C2 - M + 1,
// and the nuw flag gives X <= C2, allowing us to tighten the mask.
const APInt *AndC;
if (match(Op1, m_OneUse(m_And(m_OneUse(m_NUWSub(m_ImmConstant(C2),
                                                  m_Value(X))),
                                m_APInt(AndC))))) {
    const APInt *C1;
    if (match(Op0, m_APInt(C1))) {
        // AndC must be -M where M is a power of 2.
        APInt M = -*AndC;
        if (M.isPowerOf2()) {
            APInt C2Val = cast<ConstantInt>(C2)->getValue();
            if (C2Val.urem(M) == M - 1 && *C1 == C2Val - M + 1) {
                // Compute bound mask: bits that can be set given X <= C2.
                unsigned Log2 = (C2Val + 1).ceilLogBase2();
                APInt BoundMask = APInt::getLowBitsSet(C1->getBitWidth(), Log2);
                APInt ResultMask = *AndC & BoundMask;
                return BinaryOperator::CreateAnd(
                    X, ConstantInt::get(I.getType(), ResultMask));
            }
        }
    }
}
```

